#include<bits/stdc++.h>
using namespace std;
int a[500010];
int n,m;
vector<pair<int,int>> mp[500010];
vector<int> mp1[500010];
map<pair<int,int>,bool> mp2;
int in[500010];
stack<int> s;
bool instk[500010];
int dfn[500010],f[500010],low[500010],edcccnt,edcc[500010],siz[500010],val[500010],dfncnt;
int fa[500010][21],lg[500010],d[500010];
void dfs(int x,int f=0)
{
    d[x]=d[f]+1;
    fa[x][0]=f;
    for(int i=1;i<=lg[d[x]];i++)
    {
        fa[x][i]=fa[fa[x][i-1]][i-1];
    }
    for(int i:mp1[x])
    {
        if(i!=f)
        {
            dfs(i,x);
        }
    }
}
int lca(int x,int y)
{
    if(d[x]<d[y])
    {
        swap(x,y);
    }
    while(d[x]>d[y])
    {
        x=fa[x][lg[d[x]-d[y]]];
    }
    if(x==y)
    {
        return x;
    }
    for(int i=lg[d[x]];i>=0;i--)
    {
        if(fa[x][i]!=fa[y][i])
        {
            x=fa[x][i];
            y=fa[y][i];
        }
    }
    return fa[x][0];
}
void tarjan(int x,int fa)
{
    dfn[x]=low[x]=++dfncnt;
    instk[x]=true;
    s.push(x);
    for(auto i:mp[x])
    {
        int v=i.first,id=i.second;
        if(id==(fa^1))
        {
            continue;
        }
        if(!dfn[v])
        {
            tarjan(v,id);
            low[x]=min(low[x],low[v]);
        }
        else if(instk[v])
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
    if(low[x]==dfn[x])
    {
        edcccnt++;
        int top;
        do
        {
            top=s.top();
            s.pop();
            edcc[top]=edcccnt;
            siz[edcccnt]++;
            instk[top]=false;
        }while(top!=x);
    }
}
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=m;i++)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        mp[u].push_back(make_pair(v,i*2));
        mp[v].push_back(make_pair(u,i*2+1));
    }
    for(int i=1;i<=n;i++)
    {
        if(i>=2)
        {
            lg[i]=lg[i/2]+1;
        }
        if(!dfn[i])
        {
            tarjan(i,0);
        }
    }
    for(int u=1;u<=n;u++)
    {
        for(auto i:mp[u])
        {
            int v=i.first;
            if(edcc[u]!=edcc[v]&&!mp2[make_pair(edcc[u],edcc[v])])
            {
                mp2[make_pair(edcc[u],edcc[v])]=true;
                mp1[edcc[u]].push_back(edcc[v]);
            }
        }
    }
    dfs(1);
    int q;
    scanf("%d",&q);
    while(q--)
    {
        int u,v;
        scanf("%d%d",&u,&v);
        int l=lca(edcc[u],edcc[v]);
        printf("%d\n",d[edcc[u]]+d[edcc[v]]-d[l]*2);
    }
    return 0;
}
